metadata.command:
echo "=== 第一步：创建 eval.json 结构 ===" && \

# 创建 evals 目录
mkdir -p /root/.openclaw/workspace/memory/evals && \
echo "✓ 已创建 memory/evals 目录"

# 创建索引文件
cat > /root/.openclaw/workspace/memory/evals/INDEX.json << 'EOF'
{
  "version": "1.0.0",
  "lastUpdated": "2026-03-28T15:02:00Z",
  "skills": [
    {
      "id": "weather",
      "name": "Weather Query",
      "evalFile": "weather/eval.json",
      "status": "active",
      "currentPassRate": null,
      "trend": "new"
    },
    {
      "id": "github-pr-auto-fix",
      "name": "GitHub PR Auto Fix",
      "evalFile": "github-pr-auto-fix/eval.json",
      "status": "active",
      "currentPassRate": null,
      "trend": "new"
    },
    {
      "id": "summarize",
      "name": "Content Summarizer",
      "evalFile": "summarize/eval.json",
      "status": "active",
      "currentPassRate": null,
      "trend": "new"
    }
  ],
  "config": {
    "evalSchedule": "0 2 * * *",
    "autoAnalyze": true,
    "autoApply": false,
    "notifyOnFailure": true
  }
}
EOF

echo "✓ 已创建 INDEX.json"

# 创建 weather 的 eval.json
mkdir -p /root/.openclaw/workspace/memory/evals/weather && \
cat > /root/.openclaw/workspace/memory/evals/weather/eval.json << 'EOF'
{
  "skill_id": "weather",
  "skill_description": "查询当前天气和预报，无需 API Key",
  "version": 1,
  "assertions": [
    {
      "id": "returns_current_weather",
      "description": "返回当前天气信息",
      "type": "binary",
      "check": "output_contains_current_temp"
    },
    {
      "id": "returns_location",
      "description": "返回查询地点",
      "type": "binary",
      "check": "output_contains_location"
    },
    {
      "id": "handles_invalid_location",
      "description": "处理无效地点时返回友好错误",
      "type": "binary",
      "check": "error_message_is_friendly"
    }
  ],
  "test_cases": [
    {
      "id": "tc_001",
      "input": "北京天气",
      "expected": {
        "assertions_pass": ["returns_current_weather", "returns_location"]
      }
    },
    {
      "id": "tc_002",
      "input": "invalid_city_12345",
      "expected": {
        "assertions_pass": ["handles_invalid_location"]
      }
    }
  ],
  "run_history": []
}
EOF

echo "✓ 已创建 weather/eval.json"

# 创建 github-pr-auto-fix 的 eval.json
mkdir -p /root/.openclaw/workspace/memory/evals/github-pr-auto-fix && \
cat > /root/.openclaw/workspace/memory/evals/github-pr-auto-fix/eval.json << 'EOF'
{
  "skill_id": "github-pr-auto-fix",
  "skill_description": "自动修复 GitHub PR 中的 CI 失败和 review 评论",
  "version": 1,
  "assertions": [
    {
      "id": "webhook_received",
      "description": "Webhook 正确接收请求",
      "type": "binary",
      "check": "webhook_returns_200"
    },
    {
      "id": "pr_identified",
      "description": "正确识别 PR 信息",
      "type": "binary",
      "check": "pr_data_extracted"
    },
    {
      "id": "fix_applied",
      "description": "成功应用修复",
      "type": "binary",
      "check": "fix_commit_created"
    },
    {
      "id": "notification_sent",
      "description": "发送修复通知",
      "type": "binary",
      "check": "notification_delivered"
    }
  ],
  "test_cases": [],
  "run_history": []
}
EOF

echo "✓ 已创建 github-pr-auto-fix/eval.json"

# 创建 summarize 的 eval.json
mkdir -p /root/.openclaw/workspace/memory/evals/summarize && \
cat > /root/.openclaw/workspace/memory/evals/summarize/eval.json << 'EOF'
{
  "skill_id": "summarize",
  "skill_description": "使用 summarize CLI 摘要网页、PDF、图片、音频、YouTube",
  "version": 1,
  "assertions": [
    {
      "id": "returns_summary",
      "description": "返回摘要内容",
      "type": "binary",
      "check": "output_not_empty"
    },
    {
      "id": "summary_concise",
      "description": "摘要简洁（< 500 字）",
      "type": "binary",
      "check": "output_length_under_500"
    },
    {
      "id": "preserves_key_points",
      "description": "保留关键信息点",
      "type": "binary",
      "check": "contains_key_entities"
    }
  ],
  "test_cases": [
    {
      "id": "tc_001",
      "input": "https://example.com",
      "expected": {
        "assertions_pass": ["returns_summary", "summary_concise"]
      }
    }
  ],
  "run_history": []
}
EOF

echo "✓ 已创建 summarize/eval.json"

echo "" && \
echo "=== 验证文件结构 ===" && \
tree /root/.openclaw/workspace/memory/evals/ 2>/dev/null || \
find /root/.openclaw/workspace/memory/evals/ -type f
